from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase.
    """
    if not triples:
        return ""

    # Group triples by subject to handle related entities (e.g., country info)
    subject_triples: dict[str, list[Triple]] = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Find the monument as the main subject (look for "Monument" in subject name)
    main_subject = None
    for subj in subject_triples.keys():
        if "Monument" in subj or "Memorial" in subj or "Plack" in subj or "Battlefield" in subj:
            main_subject = subj
            break
    if main_subject is None:
        main_subject = triples[0].subject

    # Collect all clauses for comprehensive sentence building
    all_clauses: list[str] = []
    location_parts: list[str] = []
    country = ""
    state = ""
    capital = ""
    leader_info = []
    other_country_info = []

    for subject, sub_triples in subject_triples.items():
        for triple in sub_triples:
            p = triple.predicate
            o = triple.object.strip('"')  # remove surrounding quotes if present

            # Map predicates to natural‑language fragments with better phrasing
            if subject == main_subject:
                if p == "category":
                    all_clauses.append(f"which is a {o}")
                elif p in ("established", "foundingDate"):
                    all_clauses.append(f"was established on {o}")
                elif p == "inaugurationDate":
                    all_clauses.append(f"was inaugurated on {o}")
                elif p == "owner":
                    all_clauses.append(f"is owned by {o}")
                elif p == "owningOrganisation":
                    all_clauses.append(f"owned by {o}")
                elif p == "dedicatedTo":
                    all_clauses.append(f"is dedicated to {o}")
                elif p == "designer":
                    all_clauses.append(f"was designed by {o}")
                elif p == "material":
                    all_clauses.append(f"is made of {o}")
                elif p == "nativeName":
                    all_clauses.append(f'native name is "{o}"')
                elif p == "district":
                    all_clauses.append(f"in the district of {o}")
                elif p == "location":
                    location_parts.append(o)
                elif p == "municipality":
                    location_parts.append(o)
                elif p == "state":
                    state = o
                elif p == "country":
                    country = o
                elif p == "nearestCity":
                    all_clauses.append(f"nearest city is {o}")
            else:
                # Handle related entity info (country, capital, etc.)
                if p == "capital":
                    capital = o
                elif p == "leader":
                    leader_info.append(f"leader {o}")
                elif p == "leaderTitle":
                    leader_info.append(f"leader title is {o}")
                elif p == "currency":
                    other_country_info.append(f"currency is {o}")
                elif p == "largestCity":
                    other_country_info.append(f"largest city is {o}")
                elif p == "language":
                    other_country_info.append(f"language is {o}")
                elif p == "ethnicGroup":
                    other_country_info.append(f"ethnic group includes {o}")
                elif p == "religion":
                    other_country_info.append(f"religion is {o}")
                elif p == "legislature":
                    other_country_info.append(f"legislature is {o}")
                elif p in ("hasToItsNorth", "hasToItsSouthwest", "hasToItsWest", "hasToItsSoutheast"):
                    direction = p.replace("hasToIts", "")
                    other_country_info.append(f"{direction.lower()} is {o}")

    # Build location phrase
    location_text = ""
    if location_parts:
        loc_str = ", ".join(location_parts)
        if state and state not in loc_str:
            loc_str += f", {state}"
        if country and country not in loc_str:
            loc_str += f", {country}"
        location_text = f"is located in {loc_str}"

    # Build country info clause
    country_info_parts = []
    if capital:
        country_info_parts.append(f"capital {capital}")
    if leader_info:
        country_info_parts.append(", ".join(leader_info))
    if other_country_info:
        country_info_parts.append(", ".join(other_country_info))

    country_text = ""
    if country_info_parts:
        country_text = f"({', '.join(country_info_parts)})"

    # Build the final sentence by concatenating parts with proper punctuation
    sentence_parts = []

    # Main subject with location
    if location_text:
        sentence_parts.append(f"{main_subject} {location_text}")
    else:
        sentence_parts.append(main_subject)

    # Main subject descriptive clauses
    if all_clauses:
        sentence_parts.append(", ".join(all_clauses))

    # Country‑related information gathered from other entities
    country_details = []
    if country:
        country_details.append(country)
    if capital:
        country_details.append(f"its capital is {capital}")
    if leader_info:
        country_details.extend(leader_info)
    if other_country_info:
        country_details.extend(other_country_info)

    if country_details:
        sentence_parts.append("in " + ", ".join(country_details))

    sentence = " ".join(sentence_parts) + "."

    return sentence

